{
  "name": "HorariPro - Control Horari i Vacances",
  "description": "Una aplicació completa per al control horari diari i mensual, gestió de festius i planificació de vacances per a treballadors.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("No s'ha trobat l'element arrel per muntar l'aplicació");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ClockType {
  IN = 'IN',
  OUT = 'OUT'
}

export interface ClockEntry {
  id: string;
  type: ClockType;
  timestamp: number;
  location?: {
    lat: number;
    lng: number;
  };
}

export interface VacationRequest {
  id: string;
  startDate: string; // ISO string
  endDate: string;   // ISO string
  status: 'Pendent' | 'Aprovada' | 'Denegada';
  type: 'Vacances' | 'Assumptes Propis' | 'Baixa';
}

export interface Holiday {
  date: string; // YYYY-MM-DD
  name: string;
}

export type ViewType = 'dashboard' | 'calendar' | 'reports' | 'settings';

import { GoogleGenAI } from "@google/genai";
import { ClockEntry } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateMonthlyInsights = async (entries: ClockEntry[], monthName: string) => {
  if (!process.env.API_KEY) return "Configura la clau API per rebre anàlisis.";

  try {
    const prompt = `Analitza aquests registres de control horari per al mes de ${monthName} i genera un resum motivador i professional en català. 
    Registres: ${JSON.stringify(entries.slice(0, 50))}...
    L'usuari ha treballat diverses jornades. Comenta sobre la puntualitat, hores extres o suggeriments de benestar laboral.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        systemInstruction: "Ets un assistent de recursos humans amable i professional anomenat HorariPro AI. Respon sempre en català."
      }
    });

    return response.text || "No s'ha pogut generar l'anàlisi.";
  } catch (error) {
    console.error("Error generating insights:", error);
    return "Error al connectar amb el servei d'intel·ligència artificial.";
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Clock, 
  Calendar as CalendarIcon, 
  BarChart3, 
  Settings, 
  LogIn, 
  LogOut,
  ChevronLeft,
  ChevronRight,
  Plus,
  Info
} from 'lucide-react';
import { ClockType, ClockEntry, VacationRequest, ViewType } from './types';
import Dashboard from './components/Dashboard';
import CalendarView from './components/CalendarView';
import Reports from './components/Reports';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [clockEntries, setClockEntries] = useState<ClockEntry[]>([]);
  const [vacations, setVacations] = useState<VacationRequest[]>([]);
  const [isClockedIn, setIsClockedIn] = useState(false);

  // Load data from localStorage
  useEffect(() => {
    const savedEntries = localStorage.getItem('horaripro_entries');
    const savedVacations = localStorage.getItem('horaripro_vacations');
    if (savedEntries) setClockEntries(JSON.parse(savedEntries));
    if (savedVacations) setVacations(JSON.parse(savedVacations));

    // Determine current status
    if (savedEntries) {
      const entries: ClockEntry[] = JSON.parse(savedEntries);
      if (entries.length > 0) {
        setIsClockedIn(entries[entries.length - 1].type === ClockType.IN);
      }
    }
  }, []);

  // Save data to localStorage
  useEffect(() => {
    localStorage.setItem('horaripro_entries', JSON.stringify(clockEntries));
    localStorage.setItem('horaripro_vacations', JSON.stringify(vacations));
  }, [clockEntries, vacations]);

  const handleClockAction = () => {
    const newType = isClockedIn ? ClockType.OUT : ClockType.IN;
    const newEntry: ClockEntry = {
      id: crypto.randomUUID(),
      type: newType,
      timestamp: Date.now(),
    };

    // Try to get geolocation
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => {
        newEntry.location = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setClockEntries(prev => [...prev, newEntry]);
      }, () => {
        setClockEntries(prev => [...prev, newEntry]);
      });
    } else {
      setClockEntries(prev => [...prev, newEntry]);
    }

    setIsClockedIn(!isClockedIn);
  };

  const addVacation = (vac: Omit<VacationRequest, 'id' | 'status'>) => {
    const newVac: VacationRequest = {
      ...vac,
      id: crypto.randomUUID(),
      status: 'Pendent'
    };
    setVacations(prev => [...prev, newVac]);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-white border-b md:border-r border-slate-200 p-4 flex md:flex-col justify-between md:justify-start gap-4">
        <div className="flex items-center gap-2 mb-8 px-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <Clock size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tight">HorariPro</h1>
        </div>

        <div className="flex md:flex-col gap-1 overflow-x-auto md:overflow-visible">
          <NavItem 
            active={activeView === 'dashboard'} 
            onClick={() => setActiveView('dashboard')}
            icon={<BarChart3 size={20} />} 
            label="Inici" 
          />
          <NavItem 
            active={activeView === 'calendar'} 
            onClick={() => setActiveView('calendar')}
            icon={<CalendarIcon size={20} />} 
            label="Calendari" 
          />
          <NavItem 
            active={activeView === 'reports'} 
            onClick={() => setActiveView('reports')}
            icon={<Clock size={20} />} 
            label="Registres" 
          />
        </div>

        <div className="hidden md:flex flex-col mt-auto gap-4 pt-4 border-t border-slate-100">
          <div className="p-3 bg-indigo-50 rounded-xl">
            <p className="text-xs font-semibold text-indigo-700 uppercase mb-1">Estat Actual</p>
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isClockedIn ? 'bg-green-500 animate-pulse' : 'bg-slate-300'}`} />
              <span className="text-sm font-medium">{isClockedIn ? 'Treballant' : 'Fora de servei'}</span>
            </div>
          </div>
          <button 
            onClick={handleClockAction}
            className={`w-full py-3 px-4 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all shadow-sm ${
              isClockedIn 
                ? 'bg-rose-500 hover:bg-rose-600 text-white shadow-rose-200' 
                : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-200'
            }`}
          >
            {isClockedIn ? <LogOut size={18} /> : <LogIn size={18} />}
            {isClockedIn ? 'Sortida' : 'Entrada'}
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 capitalize">
              {activeView === 'dashboard' && 'Tauler de Control'}
              {activeView === 'calendar' && 'Calendari i Vacances'}
              {activeView === 'reports' && 'Historial Mensual'}
            </h2>
            <p className="text-slate-500 text-sm">
              {new Date().toLocaleDateString('ca-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
          </div>

          <div className="md:hidden">
            <button 
              onClick={handleClockAction}
              className={`p-3 rounded-full shadow-lg ${isClockedIn ? 'bg-rose-500 text-white' : 'bg-indigo-600 text-white'}`}
            >
              {isClockedIn ? <LogOut size={24} /> : <LogIn size={24} />}
            </button>
          </div>
        </header>

        <div className="max-w-6xl mx-auto">
          {activeView === 'dashboard' && (
            <Dashboard 
              entries={clockEntries} 
              isClockedIn={isClockedIn} 
              onClockAction={handleClockAction} 
            />
          )}
          {activeView === 'calendar' && (
            <CalendarView 
              vacations={vacations} 
              onAddVacation={addVacation} 
            />
          )}
          {activeView === 'reports' && (
            <Reports entries={clockEntries} />
          )}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const NavItem: React.FC<NavItemProps> = ({ active, onClick, icon, label }) => (
  <button
    onClick={onClick}
    className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium ${
      active 
        ? 'bg-indigo-50 text-indigo-700' 
        : 'text-slate-500 hover:bg-slate-100 hover:text-slate-700'
    }`}
  >
    {icon}
    <span className="hidden md:inline">{label}</span>
  </button>
);

export default App;

import React, { useMemo, useState, useEffect } from 'react';
import { ClockEntry, ClockType } from '../types';
import { generateMonthlyInsights } from '../geminiService';
import { Sparkles, ArrowUpRight, ArrowDownRight, Clock } from 'lucide-react';

interface DashboardProps {
  entries: ClockEntry[];
  isClockedIn: boolean;
  onClockAction: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ entries, isClockedIn, onClockAction }) => {
  const [aiInsights, setAiInsights] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);

  const todayEntries = useMemo(() => {
    const today = new Date().setHours(0,0,0,0);
    return entries.filter(e => new Date(e.timestamp).setHours(0,0,0,0) === today);
  }, [entries]);

  const totalMinutesToday = useMemo(() => {
    let total = 0;
    for (let i = 0; i < todayEntries.length; i += 2) {
      const start = todayEntries[i];
      const end = todayEntries[i+1];
      if (start && end && start.type === ClockType.IN && end.type === ClockType.OUT) {
        total += (end.timestamp - start.timestamp) / 60000;
      } else if (start && !end && start.type === ClockType.IN) {
        total += (Date.now() - start.timestamp) / 60000;
      }
    }
    return Math.floor(total);
  }, [todayEntries]);

  const fetchInsights = async () => {
    setLoadingAi(true);
    const month = new Date().toLocaleString('ca-ES', { month: 'long' });
    const res = await generateMonthlyInsights(entries, month);
    setAiInsights(res);
    setLoadingAi(false);
  };

  useEffect(() => {
    if (entries.length > 5 && !aiInsights) {
        fetchInsights();
    }
  }, [entries]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      {/* Quick Stats */}
      <div className="lg:col-span-2 grid grid-cols-1 sm:grid-cols-2 gap-4">
        <StatCard 
          title="Temps Avui" 
          value={`${Math.floor(totalMinutesToday / 60)}h ${totalMinutesToday % 60}m`} 
          subtitle="Jornada de 8h"
          icon={<Clock className="text-indigo-600" />}
          progress={(totalMinutesToday / 480) * 100}
        />
        <StatCard 
          title="Últim Registre" 
          value={entries.length > 0 ? new Date(entries[entries.length - 1].timestamp).toLocaleTimeString('ca-ES', { hour: '2-digit', minute: '2-digit' }) : "--:--"} 
          subtitle={entries.length > 0 ? (entries[entries.length - 1].type === ClockType.IN ? 'Entrada registrada' : 'Sortida registrada') : 'Cap registre avui'}
          icon={entries[entries.length - 1]?.type === ClockType.IN ? <ArrowUpRight className="text-green-500" /> : <ArrowDownRight className="text-rose-500" />}
        />
      </div>

      {/* AI Insights Panel */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex items-center gap-2 mb-4">
          <Sparkles size={20} className="text-indigo-500" />
          <h3 className="font-bold text-slate-800">Assistent AI</h3>
        </div>
        {loadingAi ? (
          <div className="animate-pulse space-y-2">
            <div className="h-4 bg-slate-100 rounded w-full"></div>
            <div className="h-4 bg-slate-100 rounded w-5/6"></div>
            <div className="h-4 bg-slate-100 rounded w-4/6"></div>
          </div>
        ) : (
          <p className="text-sm text-slate-600 leading-relaxed italic">
            {aiInsights || "Encara no hi ha prou dades per generar un resum automàtic. Fitxa durant uns dies per veure la màgia!"}
          </p>
        )}
        <button 
            onClick={fetchInsights}
            className="mt-4 text-xs font-semibold text-indigo-600 hover:text-indigo-800"
        >
            Actualitzar anàlisi
        </button>
      </div>

      {/* Recent Activity List */}
      <div className="lg:col-span-3 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">Activitat Recent</h3>
            <button className="text-sm text-indigo-600 font-medium hover:underline">Veure-ho tot</button>
        </div>
        <div className="divide-y divide-slate-50">
          {entries.length === 0 ? (
            <div className="p-8 text-center text-slate-400">Encara no has fitxat avui</div>
          ) : (
            entries.slice(-5).reverse().map(entry => (
              <div key={entry.id} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-full ${entry.type === ClockType.IN ? 'bg-green-50 text-green-600' : 'bg-rose-50 text-rose-600'}`}>
                    {entry.type === ClockType.IN ? <LogInIcon /> : <LogOutIcon />}
                  </div>
                  <div>
                    <p className="font-semibold text-sm">{entry.type === ClockType.IN ? 'Entrada' : 'Sortida'}</p>
                    <p className="text-xs text-slate-500">
                      {new Date(entry.timestamp).toLocaleDateString('ca-ES')} a les {new Date(entry.timestamp).toLocaleTimeString('ca-ES', { hour: '2-digit', minute: '2-digit' })}
                    </p>
                  </div>
                </div>
                {entry.location && (
                  <span className="text-[10px] bg-slate-100 px-2 py-1 rounded text-slate-500">GPS OK</span>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ title: string, value: string, subtitle: string, icon: React.ReactNode, progress?: number }> = ({ title, value, subtitle, icon, progress }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
    <div className="flex justify-between items-start mb-4">
        <div>
            <p className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">{title}</p>
            <h4 className="text-2xl font-bold text-slate-800">{value}</h4>
        </div>
        <div className="p-2 bg-slate-50 rounded-xl">
            {icon}
        </div>
    </div>
    <div className="flex items-center gap-2">
        {progress !== undefined && (
            <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 transition-all duration-500" style={{ width: `${Math.min(progress, 100)}%` }} />
            </div>
        )}
        <span className="text-xs text-slate-500">{subtitle}</span>
    </div>
  </div>
);

const LogInIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4"/><polyline points="10 17 15 12 10 7"/><line x1="15" y1="12" x2="3" y2="12"/></svg>
);

const LogOutIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
);

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { HOLIDAYS_2024 } from '../constants';
import { VacationRequest } from '../types';
import { ChevronLeft, ChevronRight, Calendar as CalIcon, Plus, Info } from 'lucide-react';

interface CalendarViewProps {
  vacations: VacationRequest[];
  onAddVacation: (vac: Omit<VacationRequest, 'id' | 'status'>) => void;
}

const CalendarView: React.FC<CalendarViewProps> = ({ vacations, onAddVacation }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showModal, setShowModal] = useState(false);
  const [newVacation, setNewVacation] = useState({
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    type: 'Vacances' as any
  });

  const monthName = currentDate.toLocaleString('ca-ES', { month: 'long', year: 'numeric' });

  const daysInMonth = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const date = new Date(year, month, 1);
    const days = [];

    // Previous month filler
    const firstDayIndex = date.getDay() === 0 ? 6 : date.getDay() - 1; // Adjust for Monday start
    for (let i = 0; i < firstDayIndex; i++) {
      days.push(null);
    }

    while (date.getMonth() === month) {
      days.push(new Date(date));
      date.setDate(date.getDate() + 1);
    }
    return days;
  }, [currentDate]);

  const isHoliday = (d: Date) => {
    const dateStr = d.toISOString().split('T')[0];
    return HOLIDAYS_2024.find(h => h.date === dateStr);
  };

  const getVacation = (d: Date) => {
    const dateStr = d.toISOString().split('T')[0];
    return vacations.find(v => dateStr >= v.startDate && dateStr <= v.endDate);
  };

  const handlePrevMonth = () => setCurrentDate(new Date(currentDate.setMonth(currentDate.getMonth() - 1)));
  const handleNextMonth = () => setCurrentDate(new Date(currentDate.setMonth(currentDate.getMonth() + 1)));

  const handleAdd = () => {
    onAddVacation(newVacation);
    setShowModal(false);
  };

  return (
    <div className="space-y-6">
      {/* Calendar Header */}
      <div className="flex flex-col sm:flex-row justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex items-center gap-4 mb-4 sm:mb-0">
          <button onClick={handlePrevMonth} className="p-2 hover:bg-slate-100 rounded-full text-slate-600 transition-colors">
            <ChevronLeft size={20} />
          </button>
          <h3 className="text-lg font-bold text-slate-800 min-w-[150px] text-center capitalize">{monthName}</h3>
          <button onClick={handleNextMonth} className="p-2 hover:bg-slate-100 rounded-full text-slate-600 transition-colors">
            <ChevronRight size={20} />
          </button>
        </div>

        <button 
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl font-semibold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
        >
          <Plus size={18} />
          Demanar Vacances
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Main Grid */}
        <div className="lg:col-span-3 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="grid grid-cols-7 gap-1 mb-2">
            {['Dll', 'Dmt', 'Dmc', 'Djt', 'Dvr', 'Dss', 'Dmg'].map(day => (
              <div key={day} className="text-center text-xs font-bold text-slate-400 py-2">{day}</div>
            ))}
          </div>
          <div className="grid grid-cols-7 gap-1">
            {daysInMonth.map((day, i) => {
              if (!day) return <div key={`empty-${i}`} className="aspect-square bg-slate-50/50 rounded-lg" />;

              const holiday = isHoliday(day);
              const vacation = getVacation(day);
              const isToday = new Date().toDateString() === day.toDateString();
              const isWeekend = day.getDay() === 0 || day.getDay() === 6;

              return (
                <div 
                  key={day.toISOString()} 
                  className={`relative aspect-square rounded-lg flex flex-col items-center justify-center border transition-all p-1
                    ${isToday ? 'border-indigo-500 bg-indigo-50/30 ring-1 ring-indigo-500' : 'border-slate-100'}
                    ${isWeekend ? 'bg-slate-50/70' : 'bg-white'}
                    ${holiday ? 'bg-rose-50 border-rose-100' : ''}
                    ${vacation ? 'bg-teal-50 border-teal-100' : ''}
                  `}
                >
                  <span className={`text-sm font-medium ${holiday ? 'text-rose-600' : vacation ? 'text-teal-600' : isWeekend ? 'text-slate-400' : 'text-slate-700'}`}>
                    {day.getDate()}
                  </span>

                  {holiday && <div className="absolute top-1 right-1 w-1.5 h-1.5 rounded-full bg-rose-500" title={holiday.name} />}
                  {vacation && <div className="absolute top-1 right-1 w-1.5 h-1.5 rounded-full bg-teal-500" title={vacation.type} />}

                  {holiday && (
                    <div className="hidden sm:block text-[8px] leading-tight text-center text-rose-500 mt-1 font-semibold truncate w-full px-1">
                      {holiday.name}
                    </div>
                  )}
                  {vacation && (
                    <div className="hidden sm:block text-[8px] leading-tight text-center text-teal-500 mt-1 font-semibold truncate w-full px-1">
                      {vacation.type}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Legend and Info */}
        <div className="space-y-4">
          <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200">
            <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Info size={18} className="text-slate-400" />
              Llegenda
            </h4>
            <ul className="space-y-3">
              <LegendItem color="bg-rose-500" label="Festius (Conveni)" />
              <LegendItem color="bg-teal-500" label="Vacances" />
              <LegendItem color="bg-indigo-500" label="Avui" />
              <LegendItem color="bg-slate-200" label="Cap de setmana" />
            </ul>
          </div>

          <div className="bg-indigo-600 p-5 rounded-2xl shadow-lg shadow-indigo-100 text-white">
            <h4 className="font-bold mb-2 flex items-center gap-2">
              <CalIcon size={18} />
              Resum Vacances
            </h4>
            <div className="space-y-1">
              <p className="text-sm text-indigo-100">Disponibles: <span className="font-bold text-white">23 dies</span></p>
              <p className="text-sm text-indigo-100">Consumits: <span className="font-bold text-white">{vacations.filter(v => v.type === 'Vacances').length} dies</span></p>
            </div>
            <div className="mt-4 pt-4 border-t border-indigo-500">
              <p className="text-[10px] uppercase font-bold tracking-wider text-indigo-200">Pròxim festiu</p>
              <p className="text-sm font-medium">Sant Joan (24 Juny)</p>
            </div>
          </div>
        </div>
      </div>

      {/* Modal Demanar Vacances */}
      {showModal && (
