import React, { useState, useEffect } from 'react';
import { 
  Clock, 
  Calendar as CalendarIcon, 
  BarChart3, 
  Settings, 
  LogIn, 
  LogOut,
  User,
  Power
} from 'lucide-react';
import { ClockType, ClockEntry, VacationRequest, ViewType, UserState } from './types';
import Dashboard from './components/Dashboard';
import CalendarView from './components/CalendarView';
import Reports from './components/Reports';
import LoginScreen from './components/LoginScreen';

const App: React.FC = () => {
  const [user, setUser] = useState<UserState>({ employeeCode: null, isAuthenticated: false });
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [allEntries, setAllEntries] = useState<ClockEntry[]>([]);
  const [allVacations, setAllVacations] = useState<VacationRequest[]>([]);
  const [isClockedIn, setIsClockedIn] = useState(false);

  // Filter data for the current user
  const currentUserEntries = allEntries.filter(e => e.employeeCode === user.employeeCode);
  const currentUserVacations = allVacations.filter(v => v.employeeCode === user.employeeCode);

  // Load data from localStorage
  useEffect(() => {
    const savedEntries = localStorage.getItem('horaripro_entries');
    const savedVacations = localStorage.getItem('horaripro_vacations');
    const savedSession = localStorage.getItem('horaripro_session');

    if (savedEntries) setAllEntries(JSON.parse(savedEntries));
    if (savedVacations) setAllVacations(JSON.parse(savedVacations));
    if (savedSession) {
      const sessionData = JSON.parse(savedSession);
      setUser(sessionData);
    }
  }, []);

  // Update Clock-in status when entries change or user changes
  useEffect(() => {
    if (user.employeeCode) {
      const entries = allEntries.filter(e => e.employeeCode === user.employeeCode);
      if (entries.length > 0) {
        setIsClockedIn(entries[entries.length - 1].type === ClockType.IN);
      } else {
        setIsClockedIn(false);
      }
    }
  }, [allEntries, user.employeeCode]);

  // Save data to localStorage
  useEffect(() => {
    localStorage.setItem('horaripro_entries', JSON.stringify(allEntries));
    localStorage.setItem('horaripro_vacations', JSON.stringify(allVacations));
  }, [allEntries, allVacations]);

  const handleLogin = (code: string) => {
    const sessionData = { employeeCode: code, isAuthenticated: true };
    setUser(sessionData);
    localStorage.setItem('horaripro_session', JSON.stringify(sessionData));
  };

  const handleLogout = () => {
    setUser({ employeeCode: null, isAuthenticated: false });
    localStorage.removeItem('horaripro_session');
  };

  const handleClockAction = () => {
    if (!user.employeeCode) return;

    const newType = isClockedIn ? ClockType.OUT : ClockType.IN;
    const newEntry: ClockEntry = {
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode,
      type: newType,
      timestamp: Date.now(),
    };

    // Try to get geolocation
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => {
        newEntry.location = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setAllEntries(prev => [...prev, newEntry]);
      }, () => {
        setAllEntries(prev => [...prev, newEntry]);
      });
    } else {
      setAllEntries(prev => [...prev, newEntry]);
    }

    setIsClockedIn(!isClockedIn);
  };

  const addVacation = (vac: Omit<VacationRequest, 'id' | 'status' | 'employeeCode'>) => {
    if (!user.employeeCode) return;
    const newVac: VacationRequest = {
      ...vac,
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode,
      status: 'Pendent'
    };
    setAllVacations(prev => [...prev, newVac]);
  };

  if (!user.isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-white border-b md:border-r border-slate-200 p-4 flex md:flex-col justify-between md:justify-start gap-4">
        <div className="flex items-center gap-2 mb-8 px-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <Clock size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tight">HorariPro</h1>
        </div>

        <div className="flex md:flex-col gap-1 overflow-x-auto md:overflow-visible">
          <NavItem 
            active={activeView === 'dashboard'} 
            onClick={() => setActiveView('dashboard')}
            icon={<BarChart3 size={20} />} 
            label="Inici" 
          />
          <NavItem 
            active={activeView === 'calendar'} 
            onClick={() => setActiveView('calendar')}
            icon={<CalendarIcon size={20} />} 
            label="Calendari" 
          />
          <NavItem 
            active={activeView === 'reports'} 
            onClick={() => setActiveView('reports')}
            icon={<Clock size={20} />} 
            label="Registres" 
          />
        </div>

        <div className="hidden md:flex flex-col mt-auto gap-3 pt-4 border-t border-slate-100">
          <div className="p-3 bg-indigo-50 rounded-xl mb-1">
            <div className="flex items-center gap-2 mb-1">
              <User size={14} className="text-indigo-600" />
              <p className="text-[10px] font-bold text-indigo-700 uppercase">Empleat #{user.employeeCode}</p>
            </div>
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isClockedIn ? 'bg-green-500 animate-pulse' : 'bg-slate-300'}`} />
              <span className="text-xs font-medium">{isClockedIn ? 'Treballant' : 'Descans'}</span>
            </div>
          </div>

          <button 
            onClick={handleClockAction}
            className={`w-full py-3 px-4 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all shadow-sm ${
              isClockedIn 
                ? 'bg-rose-500 hover:bg-rose-600 text-white' 
                : 'bg-indigo-600 hover:bg-indigo-700 text-white'
            }`}
          >
            {isClockedIn ? <LogOut size={18} /> : <LogIn size={18} />}
            {isClockedIn ? 'Sortida' : 'Entrada'}
          </button>

          <button 
            onClick={handleLogout}
            className="w-full py-2 px-4 rounded-xl font-medium text-slate-500 hover:text-rose-600 hover:bg-rose-50 flex items-center justify-center gap-2 transition-all text-sm"
          >
            <Power size={16} />
            Tancar Sessió
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 capitalize">
              {activeView === 'dashboard' && 'Tauler de Control'}
              {activeView === 'calendar' && 'Calendari i Vacances'}
              {activeView === 'reports' && 'Historial Mensual'}
            </h2>
            <p className="text-slate-500 text-sm">
              {new Date().toLocaleDateString('ca-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden sm:flex flex-col items-end">
                <span className="text-xs font-bold text-slate-400 uppercase">Usuari Actiu</span>
                <span className="text-sm font-semibold text-slate-700">ID: {user.employeeCode}</span>
            </div>
            <div className="md:hidden">
              <button 
                onClick={handleClockAction}
                className={`p-3 rounded-full shadow-lg ${isClockedIn ? 'bg-rose-500 text-white' : 'bg-indigo-600 text-white'}`}
              >
                {isClockedIn ? <LogOut size={24} /> : <LogIn size={24} />}
              </button>
            </div>
          </div>
        </header>

        <div className="max-w-6xl mx-auto">
          {activeView === 'dashboard' && (
            <Dashboard 
              entries={currentUserEntries} 
              isClockedIn={isClockedIn} 
              onClockAction={handleClockAction} 
            />
          )}
          {activeView === 'calendar' && (
            <CalendarView 
              vacations={currentUserVacations} 
              onAddVacation={addVacation} 
            />
          )}
          {activeView === 'reports' && (
            <Reports entries={currentUserEntries} employeeCode={user.employeeCode || ''} />
          )}
        </div>
      </main>
    </div>
  );
};

