import React, { useMemo } from 'react';
import { ClockEntry, ClockType } from '../types';
import { Download, FileSpreadsheet, Calendar, Share2, CloudCheck, CloudOff } from 'lucide-react';

interface ReportsProps {
  entries: ClockEntry[];
  employeeCode: string;
}

const Reports: React.FC<ReportsProps> = ({ entries, employeeCode }) => {
  const groupedByDate = useMemo(() => {
    const groups: Record<string, ClockEntry[]> = {};
    entries.forEach(entry => {
      const date = new Date(entry.timestamp).toLocaleDateString('ca-ES');
      if (!groups[date]) groups[date] = [];
      groups[date].push(entry);
    });
    return Object.entries(groups).sort((a, b) => new Date(b[1][0].timestamp).getTime() - new Date(a[1][0].timestamp).getTime());
  }, [entries]);

  const calculateHours = (dateEntries: ClockEntry[]) => {
    let total = 0;
    for (let i = 0; i < dateEntries.length; i += 2) {
      const start = dateEntries[i];
      const end = dateEntries[i+1];
      if (start && end && start.type === ClockType.IN && end.type === ClockType.OUT) {
        total += (end.timestamp - start.timestamp);
      }
    }
    const hours = Math.floor(total / 3600000);
    const minutes = Math.floor((total % 3600000) / 60000);
    return `${hours}h ${minutes}m`;
  };

  const exportToCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,";
    csvContent += "ID Empleat;Data;Tipus;Hora;Latitud;Longitud\n";
    entries.forEach(e => {
      const date = new Date(e.timestamp).toLocaleDateString('ca-ES');
      const time = new Date(e.timestamp).toLocaleTimeString('ca-ES');
      const type = e.type === ClockType.IN ? "ENTRADA" : "SORTIDA";
      csvContent += `${employeeCode};${date};${type};${time};${e.location?.lat || ""};${e.location?.lng || ""}\n`;
    });
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `HorariPro_${employeeCode}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div>
          <h3 className="font-bold text-lg text-slate-800">Empleat #{employeeCode}</h3>
          <p className="text-sm text-slate-500">Historial de fitxatges</p>
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button onClick={exportToCSV} className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-4 py-2.5 rounded-xl font-semibold hover:bg-indigo-700 transition-all">
            <Download size={18} />
            Exportar CSV
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
