import React, { useState, useMemo } from 'react';
import { HOLIDAYS_2024 } from '../constants';
import { VacationRequest } from '../types';
import { ChevronLeft, ChevronRight, Calendar as CalIcon, Plus, Info } from 'lucide-react';

interface CalendarViewProps {
  vacations: VacationRequest[];
  // Fix: Omit employeeCode from the callback argument as it is injected in App.tsx
  onAddVacation: (vac: Omit<VacationRequest, 'id' | 'status' | 'employeeCode'>) => void;
}

const CalendarView: React.FC<CalendarViewProps> = ({ vacations, onAddVacation }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showModal, setShowModal] = useState(false);
  const [newVacation, setNewVacation] = useState({
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    type: 'Vacances' as any
  });

  const monthName = currentDate.toLocaleString('ca-ES', { month: 'long', year: 'numeric' });

  const daysInMonth = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const date = new Date(year, month, 1);
    const days = [];

    // Previous month filler
    const firstDayIndex = date.getDay() === 0 ? 6 : date.getDay() - 1; // Adjust for Monday start
    for (let i = 0; i < firstDayIndex; i++) {
      days.push(null);
    }

    while (date.getMonth() === month) {
      days.push(new Date(date));
      date.setDate(date.getDate() + 1);
    }
    return days;
  }, [currentDate]);

  const isHoliday = (d: Date) => {
    const dateStr = d.toISOString().split('T')[0];
    return HOLIDAYS_2024.find(h => h.date === dateStr);
  };

  const getVacation = (d: Date) => {
    const dateStr = d.toISOString().split('T')[0];
    return vacations.find(v => dateStr >= v.startDate && dateStr <= v.endDate);
  };

  const handlePrevMonth = () => setCurrentDate(new Date(currentDate.setMonth(currentDate.getMonth() - 1)));
  const handleNextMonth = () => setCurrentDate(new Date(currentDate.setMonth(currentDate.getMonth() + 1)));

  const handleAdd = () => {
    onAddVacation(newVacation);
    setShowModal(false);
  };

  return (
    <div className="space-y-6">
      {/* Calendar Header */}
      <div className="flex flex-col sm:flex-row justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex items-center gap-4 mb-4 sm:mb-0">
          <button onClick={handlePrevMonth} className="p-2 hover:bg-slate-100 rounded-full text-slate-600 transition-colors">
            <ChevronLeft size={20} />
          </button>
          <h3 className="text-lg font-bold text-slate-800 min-w-[150px] text-center capitalize">{monthName}</h3>
          <button onClick={handleNextMonth} className="p-2 hover:bg-slate-100 rounded-full text-slate-600 transition-colors">
            <ChevronRight size={20} />
          </button>
        </div>

        <button 
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl font-semibold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
        >
          <Plus size={18} />
          Demanar Vacances
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Main Grid */}
        <div className="lg:col-span-3 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="grid grid-cols-7 gap-1 mb-2">
            {['Dll', 'Dmt', 'Dmc', 'Djt', 'Dvr', 'Dss', 'Dmg'].map(day => (
              <div key={day} className="text-center text-xs font-bold text-slate-400 py-2">{day}</div>
            ))}
          </div>
          <div className="grid grid-cols-7 gap-1">
            {daysInMonth.map((day, i) => {
              if (!day) return <div key={`empty-${i}`} className="aspect-square bg-slate-50/50 rounded-lg" />;

              const holiday = isHoliday(day);
              const vacation = getVacation(day);
              const isToday = new Date().toDateString() === day.toDateString();
              const isWeekend = day.getDay() === 0 || day.getDay() === 6;

              return (
                <div 
                  key={day.toISOString()} 
                  className={`relative aspect-square rounded-lg flex flex-col items-center justify-center border transition-all p-1
                    ${isToday ? 'border-indigo-500 bg-indigo-50/30 ring-1 ring-indigo-500' : 'border-slate-100'}
                    ${isWeekend ? 'bg-slate-50/70' : 'bg-white'}
                    ${holiday ? 'bg-rose-50 border-rose-100' : ''}
                    ${vacation ? 'bg-teal-50 border-teal-100' : ''}
                  `}
                >
                  <span className={`text-sm font-medium ${holiday ? 'text-rose-600' : vacation ? 'text-teal-600' : isWeekend ? 'text-slate-400' : 'text-slate-700'}`}>
                    {day.getDate()}
                  </span>

                  {holiday && <div className="absolute top-1 right-1 w-1.5 h-1.5 rounded-full bg-rose-500" title={holiday.name} />}
                  {vacation && <div className="absolute top-1 right-1 w-1.5 h-1.5 rounded-full bg-teal-500" title={vacation.type} />}

                  {holiday && (
                    <div className="hidden sm:block text-[8px] leading-tight text-center text-rose-500 mt-1 font-semibold truncate w-full px-1">
                      {holiday.name}
                    </div>
                  )}
                  {vacation && (
                    <div className="hidden sm:block text-[8px] leading-tight text-center text-teal-500 mt-1 font-semibold truncate w-full px-1">
                      {vacation.type}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Legend and Info */}
        <div className="space-y-4">
          <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200">
            <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Info size={18} className="text-slate-400" />
              Llegenda
            </h4>
            <ul className="space-y-3">
              <LegendItem color="bg-rose-500" label="Festius (Conveni)" />
              <LegendItem color="bg-teal-500" label="Vacances" />
              <LegendItem color="bg-indigo-500" label="Avui" />
              <LegendItem color="bg-slate-200" label="Cap de setmana" />
            </ul>
          </div>

          <div className="bg-indigo-600 p-5 rounded-2xl shadow-lg shadow-indigo-100 text-white">
            <h4 className="font-bold mb-2 flex items-center gap-2">
              <CalIcon size={18} />
              Resum Vacances
            </h4>
            <div className="space-y-1">
              <p className="text-sm text-indigo-100">Disponibles: <span className="font-bold text-white">23 dies</span></p>
              <p className="text-sm text-indigo-100">Consumits: <span className="font-bold text-white">{vacations.filter(v => v.type === 'Vacances').length} dies</span></p>
            </div>
            <div className="mt-4 pt-4 border-t border-indigo-500">
              <p className="text-[10px] uppercase font-bold tracking-wider text-indigo-200">Pròxim festiu</p>
              <p className="text-sm font-medium">Sant Joan (24 Juny)</p>
            </div>
          </div>
        </div>
      </div>

      {/* Modal Demanar Vacances */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="font-bold text-lg">Sol·licitud de Dies</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tipus</label>
                <select 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  value={newVacation.type}
                  onChange={e => setNewVacation({...newVacation, type: e.target.value as any})}
                >
                  <option>Vacances</option>
                  <option>Assumptes Propis</option>
                  <option>Baixa</option>
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Inici</label>
                  <input 
                    type="date" 
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    value={newVacation.startDate}
                    onChange={e => setNewVacation({...newVacation, startDate: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Fi</label>
                  <input 
                    type="date" 
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    value={newVacation.endDate}
                    onChange={e => setNewVacation({...newVacation, endDate: e.target.value})}
                  />
                </div>
              </div>
            </div>
            <div className="p-6 bg-slate-50 flex gap-3">
              <button onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 text-slate-600 font-semibold hover:bg-slate-200 rounded-xl transition-colors">Cancel·lar</button>
              <button onClick={handleAdd} className="flex-1 px-4 py-2 bg-indigo-600 text-white font-semibold hover:bg-indigo-700 rounded-xl transition-all shadow-md shadow-indigo-100">Sol·licitar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const LegendItem: React.FC<{ color: string, label: string }> = ({ color, label }) => (
  <li className="flex items-center gap-3">
    <div className={`w-3 h-3 rounded-full ${color}`} />
    <span className="text-sm text-slate-600 font-medium">{label}</span>
  </li>
);

export default CalendarView;

