import React, { useState } from 'react';
import { Lock, Delete, UserCircle } from 'lucide-react';

interface LoginScreenProps {
  onLogin: (code: string, name?: string) => void;
  savedName: string | null;
  savedCode: string | null;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onLogin, savedName, savedCode }) => {
  const [pin, setPin] = useState('');
  const [name, setName] = useState('');
  const [isFirstLogin] = useState(!savedName);

  const handleNumberClick = (num: string) => {
    if (pin.length < 4) {
      const newPin = pin + num;
      setPin(newPin);
      if (newPin.length === 4) {
        if (isFirstLogin && !name.trim()) {
          // Si és el primer cop i no hi ha nom, demanar-lo abans de deixar entrar
          alert("Per favor, introdueix el teu nom primer.");
          setPin('');
          return;
        }
        setTimeout(() => onLogin(newPin, isFirstLogin ? name : undefined), 300);
      }
    }
  };

  const handleDelete = () => {
    setPin(pin.slice(0, -1));
  };

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white rounded-[2rem] shadow-2xl overflow-hidden p-6 sm:p-8 animate-in fade-in zoom-in duration-300">
