    isAuthenticated: false, 
    sheetsUrl: '' 
  });
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [allEntries, setAllEntries] = useState<ClockEntry[]>([]);
  const [allVacations, setAllVacations] = useState<VacationRequest[]>([]);
  const [isClockedIn, setIsClockedIn] = useState(false);

  const currentUserEntries = allEntries.filter(e => e.employeeCode === user.employeeCode);
  const currentUserVacations = allVacations.filter(v => v.employeeCode === user.employeeCode);

  useEffect(() => {
    const savedEntries = localStorage.getItem('horaripro_entries');
    const savedVacations = localStorage.getItem('horaripro_vacations');
    const savedSession = localStorage.getItem('horaripro_session');

    if (savedEntries) setAllEntries(JSON.parse(savedEntries));
    if (savedVacations) setAllVacations(JSON.parse(savedVacations));
    if (savedSession) {
      setUser(JSON.parse(savedSession));
    }
  }, []);

  useEffect(() => {
    if (user.employeeCode) {
      const entries = allEntries.filter(e => e.employeeCode === user.employeeCode);
      setIsClockedIn(entries.length > 0 && entries[entries.length - 1].type === ClockType.IN);
    }
  }, [allEntries, user.employeeCode]);

  useEffect(() => {
    localStorage.setItem('horaripro_entries', JSON.stringify(allEntries));
    localStorage.setItem('horaripro_vacations', JSON.stringify(allVacations));
    if (user.isAuthenticated) {
      localStorage.setItem('horaripro_session', JSON.stringify(user));
    }
  }, [allEntries, allVacations, user]);

  const handleLogin = (code: string, name?: string) => {
    const sessionData = { 
      ...user, 
      employeeCode: code, 
      employeeName: name || user.employeeName, 
      isAuthenticated: true 
    };
    setUser(sessionData);
  };

  const handleLogout = () => {
    setUser(prev => ({ ...prev, isAuthenticated: false }));
  };

  const handleResetProfile = () => {
    if (window.confirm("Estàs segur que vols donar-te de baixa d'aquest dispositiu? S'esborrarà el teu nom i el teu PIN d'aquí.")) {
      localStorage.removeItem('horaripro_session');
      setUser({ employeeCode: null, employeeName: null, isAuthenticated: false, sheetsUrl: user.sheetsUrl });
    }
  };

  const handleClearHistory = () => {
    if (window.confirm("Vols esborrar l'historial de fitxatges d'aquest dispositiu? (Això no esborrarà les dades enviades a l'Excel)")) {
      setAllEntries([]);
      localStorage.removeItem('horaripro_entries');
    }
  };

  const handleClockAction = async () => {
    if (!user.employeeCode || !user.employeeName) return;

    const newType = isClockedIn ? ClockType.OUT : ClockType.IN;
    const newEntry: ClockEntry = {
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode,
      employeeName: user.employeeName,
      type: newType,
      timestamp: Date.now(),
      syncStatus: 'Pendent'
    };

    const updateWithGeo = (pos?: GeolocationPosition) => {
      if (pos) {
        newEntry.location = { lat: pos.coords.latitude, lng: pos.coords.longitude };
      }

      setAllEntries(prev => [...prev, newEntry]);

      if (user.sheetsUrl) {
        syncToSheets(newEntry, user.sheetsUrl).then(success => {
          if (success) {
            setAllEntries(prev => prev.map(e => e.id === newEntry.id ? { ...e, syncStatus: 'Sincronitzat' } : e));
          }
        });
      }
    };

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => updateWithGeo(pos), () => updateWithGeo());
    } else {
      updateWithGeo();
    }

    setIsClockedIn(!isClockedIn);
  };

  const addVacation = (vac: Omit<VacationRequest, 'id' | 'status' | 'employeeCode'>) => {
    if (!user.employeeCode) return;
    const newVac: VacationRequest = {
      ...vac,
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode,
      status: 'Pendent'
    };
    setAllVacations(prev => [...prev, newVac]);
  };

  const updateSheetsUrl = (url: string) => {
    setUser(prev => ({ ...prev, sheetsUrl: url }));
  };

  if (!user.isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} savedName={user.employeeName} savedCode={user.employeeCode} />;
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
      <nav className="w-full md:w-64 bg-white border-b md:border-r border-slate-200 p-4 flex md:flex-col justify-between md:justify-start gap-4">
        <div className="flex items-center gap-2 mb-8 px-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <Clock size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tight">HorariPro</h1>
        </div>

        <div className="flex md:flex-col gap-1 overflow-x-auto md:overflow-visible">
          <NavItem active={activeView === 'dashboard'} onClick={() => setActiveView('dashboard')} icon={<BarChart3 size={20} />} label="Inici" />
          <NavItem active={activeView === 'calendar'} onClick={() => setActiveView('calendar')} icon={<CalendarIcon size={20} />} label="Calendari" />
          <NavItem active={activeView === 'reports'} onClick={() => setActiveView('reports')} icon={<Clock size={20} />} label="Registres" />
          <NavItem active={activeView === 'settings'} onClick={() => setActiveView('settings')} icon={<Settings size={20} />} label="Config." />
        </div>

        <div className="hidden md:flex flex-col mt-auto gap-3 pt-4 border-t border-slate-100">
          <div className="p-3 bg-indigo-50 rounded-xl mb-1">
            <p className="text-[10px] font-bold text-indigo-700 uppercase mb-1">{user.employeeName}</p>
            <div className="flex items-center gap-2 mb-1">
              <User size={14} className="text-indigo-600" />
              <p className="text-[10px] font-bold text-slate-500 uppercase">ID: {user.employeeCode}</p>
            </div>
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isClockedIn ? 'bg-green-500 animate-pulse' : 'bg-slate-300'}`} />
              <span className="text-xs font-medium">{isClockedIn ? 'En servei' : 'Aturat'}</span>
            </div>
          </div>

          <button onClick={handleClockAction} className={`w-full py-3 px-4 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all ${isClockedIn ? 'bg-rose-500 text-white' : 'bg-indigo-600 text-white'}`}>
            {isClockedIn ? <LogOut size={18} /> : <LogIn size={18} />}
            {isClockedIn ? 'Sortida' : 'Entrada'}
          </button>

          <button onClick={handleLogout} className="w-full py-2 px-4 rounded-xl font-medium text-slate-500 hover:text-rose-600 hover:bg-rose-50 flex items-center justify-center gap-2 transition-all text-sm">
            <Power size={16} />
            Surt
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 capitalize">
              {activeView === 'dashboard' && 'Tauler'}
              {activeView === 'calendar' && 'Calendari'}
              {activeView === 'reports' && 'Registres'}
              {activeView === 'settings' && 'Configuració'}
            </h2>
          </div>
          <div className="md:hidden">
            <button onClick={handleClockAction} className={`p-3 rounded-full shadow-lg ${isClockedIn ? 'bg-rose-500 text-white' : 'bg-indigo-600 text-white'}`}>
              {isClockedIn ? <LogOut size={24} /> : <LogIn size={24} />}
            </button>
          </div>
        </header>

        <div className="max-w-6xl mx-auto">
          {activeView === 'dashboard' && <Dashboard entries={currentUserEntries} isClockedIn={isClockedIn} onClockAction={handleClockAction} />}
          {activeView === 'calendar' && <CalendarView vacations={currentUserVacations} onAddVacation={addVacation} />}
          {activeView === 'reports' && <Reports entries={currentUserEntries} employeeCode={user.employeeCode || ''} />}
          {activeView === 'settings' && (
            <SettingsView 
              sheetsUrl={user.sheetsUrl || ''} 
              onUpdateUrl={updateSheetsUrl} 
              onResetProfile={handleResetProfile}
              onClearHistory={handleClearHistory}
              employeeName={user.employeeName || ''}
            />
          )}
        </div>
      </main>
    </div>
  );
};

