import CalendarView from './components/CalendarView';
import Reports from './components/Reports';
import LoginScreen from './components/LoginScreen';
import SettingsView from './components/SettingsView';
import VacationAdmin from './components/VacationAdmin';
import { syncToSheets } from './sheetsService';

const App: React.FC = () => {
  const [user, setUser] = useState<UserState>({ 
    employeeCode: null, 
    employeeName: null, 
    isAuthenticated: false, 
    sheetsUrl: '',
    isAdmin: false
  });
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [allEntries, setAllEntries] = useState<ClockEntry[]>([]);
  const [allVacations, setAllVacations] = useState<VacationRequest[]>([]);
  const [isClockedIn, setIsClockedIn] = useState(false);

  useEffect(() => {
    const savedEntries = localStorage.getItem('horaripro_entries');
    const savedVacations = localStorage.getItem('horaripro_vacations');
    const savedSession = localStorage.getItem('horaripro_session');

    if (savedEntries) setAllEntries(JSON.parse(savedEntries));
    if (savedVacations) setAllVacations(JSON.parse(savedVacations));
    if (savedSession) {
      setUser(JSON.parse(savedSession));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('horaripro_entries', JSON.stringify(allEntries));
    localStorage.setItem('horaripro_vacations', JSON.stringify(allVacations));
    if (user.isAuthenticated) {
      localStorage.setItem('horaripro_session', JSON.stringify(user));
    }
  }, [allEntries, allVacations, user]);

  useEffect(() => {
    if (user.employeeCode) {
      const entries = allEntries.filter(e => e.employeeCode === user.employeeCode);
      setIsClockedIn(entries.length > 0 && entries[entries.length - 1].type === ClockType.IN);
    }
  }, [allEntries, user.employeeCode]);

  const handleLogin = (code: string, name?: string) => {
    const isAdmin = code === '9999'; // Codi especial per admin
    const sessionData = { 
      ...user, 
      employeeCode: code, 
      employeeName: name || user.employeeName, 
      isAuthenticated: true,
      isAdmin: isAdmin || user.isAdmin
    };
    setUser(sessionData);
  };

  const handleLogout = () => {
    setUser(prev => ({ ...prev, isAuthenticated: false }));
  };

  const handleResetProfile = () => {
    if (window.confirm("Vols donar-te de baixa d'aquest dispositiu?")) {
      localStorage.removeItem('horaripro_session');
      setUser({ employeeCode: null, employeeName: null, isAuthenticated: false, sheetsUrl: user.sheetsUrl, isAdmin: false });
    }
  };

  const handleClockAction = async () => {
    if (!user.employeeCode || !user.employeeName) return;
    const newType = isClockedIn ? ClockType.OUT : ClockType.IN;
    const newEntry: ClockEntry = {
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode,
      employeeName: user.employeeName,
      type: newType,
      timestamp: Date.now(),
      syncStatus: 'Pendent'
    };

    const updateWithGeo = (pos?: GeolocationPosition) => {
      if (pos) newEntry.location = { lat: pos.coords.latitude, lng: pos.coords.longitude };
      setAllEntries(prev => [...prev, newEntry]);
      if (user.sheetsUrl) {
        syncToSheets(newEntry, user.sheetsUrl).then(success => {
          if (success) {
            setAllEntries(prev => prev.map(e => e.id === newEntry.id ? { ...e, syncStatus: 'Sincronitzat' } : e));
          }
        });
      }
    };

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => updateWithGeo(pos), () => updateWithGeo());
    } else {
      updateWithGeo();
    }
  };

  const addVacation = (vac: Omit<VacationRequest, 'id' | 'status' | 'employeeCode' | 'employeeName'>) => {
    const newVac: VacationRequest = {
      ...vac,
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode || '0000',
      employeeName: user.employeeName || 'Desconegut',
      status: 'Pendent'
    };
    setAllVacations(prev => [...prev, newVac]);
  };

  const updateVacationStatus = (id: string, status: 'Aprovada' | 'Denegada') => {
    setAllVacations(prev => prev.map(v => v.id === id ? { ...v, status } : v));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
      <nav className="w-full md:w-64 bg-white border-b md:border-r border-slate-200 p-4 flex md:flex-col gap-4">
        <div className="flex items-center gap-2 mb-8 px-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <Clock size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tight">HorariPro</h1>
        </div>

        <div className="flex md:flex-col gap-1 overflow-x-auto">
          <NavItem active={activeView === 'dashboard'} onClick={() => setActiveView('dashboard')} icon={<BarChart3 size={20} />} label="Inici" />
          <NavItem active={activeView === 'calendar'} onClick={() => setActiveView('calendar')} icon={<CalendarIcon size={20} />} label="Calendari" />
          <NavItem active={activeView === 'reports'} onClick={() => setActiveView('reports')} icon={<Clock size={20} />} label="Registres" />
          {user.isAdmin && <NavItem active={activeView === 'admin'} onClick={() => setActiveView('admin')} icon={<ShieldCheck size={20} />} label="Gestió" />}
          <NavItem active={activeView === 'settings'} onClick={() => setActiveView('settings')} icon={<Settings size={20} />} label="Config." />
        </div>

        <div className="hidden md:flex flex-col mt-auto gap-3 pt-4 border-t border-slate-100">
          <div className="p-3 bg-indigo-50 rounded-xl">
             <p className="text-[10px] font-bold text-indigo-700 uppercase">{user.employeeName} {user.isAdmin && "(Admin)"}</p>
             <p className="text-[10px] text-slate-500">ID: {user.employeeCode}</p>
          </div>
          <button onClick={handleClockAction} className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 ${isClockedIn ? 'bg-rose-500 text-white' : 'bg-indigo-600 text-white'}`}>
            {isClockedIn ? <LogOut size={18} /> : <LogIn size={18} />}
            {isClockedIn ? 'Sortida' : 'Entrada'}
          </button>
          <button onClick={handleLogout} className="text-xs text-slate-400 hover:text-rose-500 flex items-center justify-center gap-2">
            <Power size={14} /> Tancar Sessió
