import React, { useState, useMemo } from 'react';
import { HOLIDAYS_2024 } from '../constants';
import { VacationRequest } from '../types';
import { ChevronLeft, ChevronRight, Calendar as CalIcon, Plus, Info, User } from 'lucide-react';

interface CalendarViewProps {
  vacations: VacationRequest[];
  currentUserId: string;
  onAddVacation: (vac: Omit<VacationRequest, 'id' | 'status' | 'employeeCode' | 'employeeName'>) => void;
}

const CalendarView: React.FC<CalendarViewProps> = ({ vacations, currentUserId, onAddVacation }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showModal, setShowModal] = useState(false);
  const [newVacation, setNewVacation] = useState({
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    type: 'Vacances' as any
  });

  const monthName = currentDate.toLocaleString('ca-ES', { month: 'long', year: 'numeric' });

  const daysInMonth = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const date = new Date(year, month, 1);
    const days = [];
    const firstDayIndex = date.getDay() === 0 ? 6 : date.getDay() - 1;
    for (let i = 0; i < firstDayIndex; i++) days.push(null);
    while (date.getMonth() === month) {
      days.push(new Date(date));
      date.setDate(date.getDate() + 1);
    }
    return days;
  }, [currentDate]);

  const isHoliday = (d: Date) => {
    const dateStr = d.toISOString().split('T')[0];
    return HOLIDAYS_2024.find(h => h.date === dateStr);
  };

  // Obtenim totes les vacances que s'han de mostrar per un dia concret
  const getDayVacations = (d: Date) => {
    const dateStr = d.toISOString().split('T')[0];
    return vacations.filter(v => {
      const isInRange = dateStr >= v.startDate && dateStr <= v.endDate;
      // Mostrem: Les meves (tots els estats) + Les dels altres (només aprovades)
      if (v.employeeCode === currentUserId) return isInRange;
      return isInRange && v.status === 'Aprovada';
    });
  };

  const handlePrevMonth = () => setCurrentDate(new Date(currentDate.setMonth(currentDate.getMonth() - 1)));
  const handleNextMonth = () => setCurrentDate(new Date(currentDate.setMonth(currentDate.getMonth() + 1)));

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:row justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-200 gap-4">
        <div className="flex items-center gap-4">
          <button onClick={handlePrevMonth} className="p-2 hover:bg-slate-100 rounded-full"><ChevronLeft size={20} /></button>
          <h3 className="text-lg font-bold min-w-[150px] text-center capitalize">{monthName}</h3>
          <button onClick={handleNextMonth} className="p-2 hover:bg-slate-100 rounded-full"><ChevronRight size={20} /></button>
        </div>
        <button onClick={() => setShowModal(true)} className="flex items-center gap-2 bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-indigo-100 transition-all active:scale-95">
          <Plus size={18} /> Demanar Vacances
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="grid grid-cols-7 gap-1 mb-2">
            {['Dll', 'Dmt', 'Dmc', 'Djt', 'Dvr', 'Dss', 'Dmg'].map(day => (
              <div key={day} className="text-center text-[10px] font-bold text-slate-400 py-2 uppercase">{day}</div>
            ))}
          </div>
          <div className="grid grid-cols-7 gap-1">
            {daysInMonth.map((day, i) => {
              if (!day) return <div key={`empty-${i}`} className="aspect-square bg-slate-50/50 rounded-lg" />;

              const holiday = isHoliday(day);
              const dayVacations = getDayVacations(day);
              const isToday = new Date().toDateString() === day.toDateString();
              const isWeekend = day.getDay() === 0 || day.getDay() === 6;

              return (
                <div key={day.toISOString()} className={`relative aspect-square rounded-lg flex flex-col items-center justify-start border transition-all p-1 overflow-hidden
                    ${isToday ? 'border-indigo-500 bg-indigo-50/30' : 'border-slate-100'}
                    ${isWeekend ? 'bg-slate-50/70' : 'bg-white'}
                    ${holiday ? 'bg-rose-50' : ''}
                  `}>
                  <span className={`text-xs font-bold ${holiday ? 'text-rose-600' : isWeekend ? 'text-slate-400' : 'text-slate-700'}`}>
                    {day.getDate()}
                  </span>

                  <div className="mt-1 w-full space-y-0.5">
                    {holiday && <div className="text-[7px] bg-rose-500 text-white px-1 rounded truncate leading-tight">{holiday.name}</div>}
                    {dayVacations.map(v => (
                      <div key={v.id} className={`text-[7px] px-1 rounded truncate leading-tight font-medium ${
                        v.employeeCode === currentUserId 
                          ? 'bg-teal-500 text-white' 
                          : 'bg-slate-200 text-slate-600'
                      }`}>
                        {v.employeeCode === currentUserId ? 'Jo' : v.employeeName.split(' ')[0]}
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="space-y-4">
          <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200">
            <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><Info size={16} /> Llegenda</h4>
            <ul className="space-y-2">
              <li className="flex items-center gap-2 text-xs"><div className="w-3 h-3 rounded bg-teal-500" /> Les meves</li>
              <li className="flex items-center gap-2 text-xs"><div className="w-3 h-3 rounded bg-slate-200" /> Companys (Aprovades)</li>
              <li className="flex items-center gap-2 text-xs"><div className="w-3 h-3 rounded bg-rose-500" /> Festius</li>
            </ul>
          </div>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl p-6">
            <h3 className="font-bold text-lg mb-4">Nova Sol·licitud</h3>
            <div className="space-y-4">
              <select className="w-full bg-slate-50 p-2 rounded-lg border" value={newVacation.type} onChange={e => setNewVacation({...newVacation, type: e.target.value as any})}>
                <option>Vacances</option><option>Assumptes Propis</option><option>Baixa</option>
              </select>
              <div className="grid grid-cols-2 gap-4">
                <input type="date" className="w-full bg-slate-50 p-2 rounded-lg border" value={newVacation.startDate} onChange={e => setNewVacation({...newVacation, startDate: e.target.value})} />
                <input type="date" className="w-full bg-slate-50 p-2 rounded-lg border" value={newVacation.endDate} onChange={e => setNewVacation({...newVacation, endDate: e.target.value})} />
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowModal(false)} className="flex-1 p-2 font-bold text-slate-500">Cancel·lar</button>
                <button onClick={() => { onAddVacation(newVacation); setShowModal(false); }} className="flex-1 bg-indigo-600 text-white p-2 rounded-lg font-bold">Enviar</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CalendarView;

import React from 'react';
import { VacationRequest } from '../types';
import { Check, X, Clock, User } from 'lucide-react';

interface VacationAdminProps {
  vacations: VacationRequest[];
  onUpdateStatus: (id: string, status: 'Aprovada' | 'Denegada') => void;
}

const VacationAdmin: React.FC<VacationAdminProps> = ({ vacations, onUpdateStatus }) => {
  const pending = vacations.filter(v => v.status === 'Pendent');
  const processed = vacations.filter(v => v.status !== 'Pendent').reverse();

  return (
    <div className="space-y-8">
      <section>
        <h3 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
          <Clock className="text-amber-500" /> Sol·licituds Pendents
        </h3>
        {pending.length === 0 ? (
          <div className="bg-white p-8 rounded-3xl border border-dashed border-slate-200 text-center text-slate-400">
            No hi ha cap petició pendent de revisió.
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {pending.map(v => (
              <div key={v.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 flex flex-col justify-between">
                <div>
                  <div className="flex items-center gap-3 mb-3">
                    <div className="w-10 h-10 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600">
                      <User size={20} />
                    </div>
                    <div>
                      <p className="font-bold text-slate-800">{v.employeeName}</p>
                      <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">{v.type}</p>
                    </div>
                  </div>
                  <div className="p-3 bg-slate-50 rounded-xl mb-4">
                    <p className="text-sm font-medium text-slate-600">Del {new Date(v.startDate).toLocaleDateString('ca-ES')} al {new Date(v.endDate).toLocaleDateString('ca-ES')}</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => onUpdateStatus(v.id, 'Aprovada')} className="flex-1 bg-green-500 text-white py-2 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-green-600 transition-colors">
                    <Check size={18} /> Aprovar
                  </button>
                  <button onClick={() => onUpdateStatus(v.id, 'Denegada')} className="flex-1 bg-rose-50 text-rose-500 py-2 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-rose-100 transition-colors">
                    <X size={18} /> Denegar
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      <section>
        <h3 className="text-lg font-bold text-slate-700 mb-4">Historial de Respostes</h3>
        <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-[10px] font-bold text-slate-400 uppercase">
              <tr>
                <th className="p-4">Treballador</th>
                <th className="p-4">Dates</th>
                <th className="p-4 text-right">Estat</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {processed.map(v => (
                <tr key={v.id}>
                  <td className="p-4 font-bold text-sm text-slate-700">{v.employeeName}</td>
                  <td className="p-4 text-xs text-slate-500">
                    {new Date(v.startDate).toLocaleDateString('ca-ES')} - {new Date(v.endDate).toLocaleDateString('ca-ES')}
                  </td>
                  <td className="p-4 text-right">
                    <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase ${
                      v.status === 'Aprovada' ? 'bg-green-50 text-green-600' : 'bg-rose-50 text-rose-600'
                    }`}>
                      {v.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );
};

export default VacationAdmin;

