import React, { useState, useEffect } from 'react';
import { 
  Clock, 
  Calendar as CalendarIcon, 
  BarChart3, 
  Settings, 
  LogIn, 
  LogOut,
  User,
  Power,
  ShieldCheck,
  Fingerprint
} from 'lucide-react';
import { ClockType, ClockEntry, VacationRequest, ViewType, UserState } from './types';
import Dashboard from './components/Dashboard';
import CalendarView from './components/CalendarView';
import Reports from './components/Reports';
import LoginScreen from './components/LoginScreen';
import SettingsView from './components/SettingsView';
import VacationAdmin from './components/VacationAdmin';
import { syncToSheets } from './sheetsService';

const App: React.FC = () => {
  const [user, setUser] = useState<UserState>({ 
    employeeCode: null, 
    employeeName: null, 
    isAuthenticated: false, 
    sheetsUrl: '',
    isAdmin: false
  });
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [allEntries, setAllEntries] = useState<ClockEntry[]>([]);
  const [allVacations, setAllVacations] = useState<VacationRequest[]>([]);
  const [isClockedIn, setIsClockedIn] = useState(false);

  useEffect(() => {
    const savedEntries = localStorage.getItem('horaripro_entries');
    const savedVacations = localStorage.getItem('horaripro_vacations');
    const savedSession = localStorage.getItem('horaripro_session');

    if (savedEntries) setAllEntries(JSON.parse(savedEntries));
    if (savedVacations) setAllVacations(JSON.parse(savedVacations));
    if (savedSession) {
      const session = JSON.parse(savedSession);
      setUser({ ...session, isAuthenticated: false });
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('horaripro_entries', JSON.stringify(allEntries));
    localStorage.setItem('horaripro_vacations', JSON.stringify(allVacations));
    const { isAuthenticated, ...profileData } = user;
    if (profileData.employeeCode) {
      localStorage.setItem('horaripro_session', JSON.stringify(profileData));
    }
  }, [allEntries, allVacations, user]);

  useEffect(() => {
    if (user.employeeCode) {
      const entries = allEntries.filter(e => e.employeeCode === user.employeeCode);
      setIsClockedIn(entries.length > 0 && entries[entries.length - 1].type === ClockType.IN);
    }
  }, [allEntries, user.employeeCode]);

  const handleLogin = (code: string, name?: string) => {
    const isAdmin = code === '9999';
    setUser(prev => ({ 
      ...prev, 
      employeeCode: code, 
      employeeName: name || prev.employeeName, 
      isAuthenticated: true,
      isAdmin: isAdmin || prev.isAdmin
    }));
  };

  const handleLogout = () => {
    setUser(prev => ({ ...prev, isAuthenticated: false }));
  };

  const handleResetProfile = () => {
    if (window.confirm("Vols eliminar completament el teu perfil d'aquest dispositiu?")) {
      localStorage.removeItem('horaripro_session');
      setUser({ employeeCode: null, employeeName: null, isAuthenticated: false, sheetsUrl: user.sheetsUrl, isAdmin: false });
    }
  };

  const handleClockAction = async () => {
    if (!user.employeeCode || !user.employeeName) return;
    const newType = isClockedIn ? ClockType.OUT : ClockType.IN;
    const newEntry: ClockEntry = {
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode,
      employeeName: user.employeeName,
      type: newType,
      timestamp: Date.now(),
      syncStatus: 'Pendent'
    };

    const updateWithGeo = (pos?: GeolocationPosition) => {
      if (pos) newEntry.location = { lat: pos.coords.latitude, lng: pos.coords.longitude };
      setAllEntries(prev => [...prev, newEntry]);
      if (user.sheetsUrl) {
        syncToSheets(newEntry, user.sheetsUrl).then(success => {
          if (success) {
            setAllEntries(prev => prev.map(e => e.id === newEntry.id ? { ...e, syncStatus: 'Sincronitzat' } : e));
          }
        });
      }
    };

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => updateWithGeo(pos), () => updateWithGeo());
    } else {
      updateWithGeo();
    }
  };

  const addVacation = (vac: Omit<VacationRequest, 'id' | 'status' | 'employeeCode' | 'employeeName'>) => {
    const newVac: VacationRequest = {
      ...vac,
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode || '0000',
      employeeName: user.employeeName || 'Desconegut',
      status: 'Pendent'
    };
    setAllVacations(prev => [...prev, newVac]);
  };

  const updateVacationStatus = (id: string, status: 'Aprovada' | 'Denegada') => {
    setAllVacations(prev => prev.map(v => v.id === id ? { ...v, status } : v));
  };

  if (!user.isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} savedName={user.employeeName} savedCode={user.employeeCode} />;
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900 pb-20 md:pb-0">
      <nav className="w-full md:w-64 bg-white border-b md:border-r border-slate-200 p-4 flex md:flex-col gap-4 sticky top-0 z-30">
        <div className="flex items-center gap-2 mb-0 md:mb-8 px-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <Clock size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tight">HorariPro</h1>
        </div>

        <div className="flex md:flex-col gap-1 overflow-x-auto">
          <NavItem active={activeView === 'dashboard'} onClick={() => setActiveView('dashboard')} icon={<BarChart3 size={20} />} label="Inici" />
          <NavItem active={activeView === 'calendar'} onClick={() => setActiveView('calendar')} icon={<CalendarIcon size={20} />} label="Calendari" />
          <NavItem active={activeView === 'reports'} onClick={() => setActiveView('reports')} icon={<Clock size={20} />} label="Registres" />
          {user.isAdmin && <NavItem active={activeView === 'admin'} onClick={() => setActiveView('admin')} icon={<ShieldCheck size={20} />} label="Gestió" />}
          <NavItem active={activeView === 'settings'} onClick={() => setActiveView('settings')} icon={<Settings size={20} />} label="Config." />
        </div>

        <div className="hidden md:flex flex-col mt-auto gap-3 pt-4 border-t border-slate-100">
          <div className="p-3 bg-indigo-50 rounded-xl">
             <p className="text-[10px] font-bold text-indigo-700 uppercase">{user.employeeName} {user.isAdmin && "(Admin)"}</p>
             <p className="text-[10px] text-slate-500">ID: {user.employeeCode}</p>
          </div>
          <button onClick={handleClockAction} className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-transform active:scale-95 ${isClockedIn ? 'bg-rose-500 text-white shadow-rose-100' : 'bg-indigo-600 text-white shadow-indigo-100 shadow-lg'}`}>
            {isClockedIn ? <LogOut size={18} /> : <LogIn size={18} />}
            {isClockedIn ? 'Sortida' : 'Entrada'}
          </button>
          <button onClick={handleLogout} className="text-xs text-slate-400 hover:text-rose-500 flex items-center justify-center gap-2 transition-colors">
            <Power size={14} /> Tancar Sessió
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {activeView === 'dashboard' && <Dashboard entries={allEntries.filter(e => e.employeeCode === user.employeeCode)} isClockedIn={isClockedIn} onClockAction={handleClockAction} />}
          {activeView === 'calendar' && <CalendarView vacations={allVacations} currentUserId={user.employeeCode || ''} onAddVacation={addVacation} />}
          {activeView === 'reports' && <Reports entries={allEntries.filter(e => e.employeeCode === user.employeeCode)} employeeCode={user.employeeCode || ''} />}
          {activeView === 'admin' && <VacationAdmin vacations={allVacations} onUpdateStatus={updateVacationStatus} />}
          {activeView === 'settings' && <SettingsView sheetsUrl={user.sheetsUrl || ''} onUpdateUrl={(url) => setUser({...user, sheetsUrl: url})} onResetProfile={handleResetProfile} onClearHistory={() => setAllEntries([])} employeeName={user.employeeName || ''} />}
        </div>
      </main>

      {/* Botó flotant de fitxatge per a mòbils */}
      <div className="fixed bottom-6 right-6 md:hidden z-40">
        <button 
          onClick={handleClockAction} 
          className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 ${isClockedIn ? 'bg-rose-500 text-white ring-4 ring-rose-100' : 'bg-indigo-600 text-white ring-4 ring-indigo-100'}`}
        >
          {isClockedIn ? <LogOut size={28} /> : <Fingerprint size={28} />}
        </button>
      </div>
    </div>
  );
};

const NavItem = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium whitespace-nowrap ${active ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-100'}`}>
    {icon} <span>{label}</span>
  </button>
);

export default App;

import React, { useMemo, useState, useEffect } from 'react';
import { ClockEntry, ClockType } from '../types';
import { generateMonthlyInsights } from '../geminiService';
import { Sparkles, ArrowUpRight, ArrowDownRight, Clock, Fingerprint, LogIn, LogOut } from 'lucide-react';

interface DashboardProps {
  entries: ClockEntry[];
  isClockedIn: boolean;
  onClockAction: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ entries, isClockedIn, onClockAction }) => {
  const [aiInsights, setAiInsights] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);

  const todayEntries = useMemo(() => {
    const today = new Date().setHours(0,0,0,0);
    return entries.filter(e => new Date(e.timestamp).setHours(0,0,0,0) === today);
  }, [entries]);

  const totalMinutesToday = useMemo(() => {
    let total = 0;
    for (let i = 0; i < todayEntries.length; i += 2) {
      const start = todayEntries[i];
      const end = todayEntries[i+1];
      if (start && end && start.type === ClockType.IN && end.type === ClockType.OUT) {
        total += (end.timestamp - start.timestamp) / 60000;
      } else if (start && !end && start.type === ClockType.IN) {
        total += (Date.now() - start.timestamp) / 60000;
      }
    }
    return Math.floor(total);
  }, [todayEntries]);

  const fetchInsights = async () => {
    setLoadingAi(true);
    const month = new Date().toLocaleString('ca-ES', { month: 'long' });
    const res = await generateMonthlyInsights(entries, month);
    setAiInsights(res);
    setLoadingAi(false);
  };

  useEffect(() => {
    if (entries.length > 5 && !aiInsights) {
        fetchInsights();
    }
  }, [entries]);

  return (
    <div className="space-y-6">
      {/* Botó de fitxar principal (Mobile & Desktop) */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-200 flex flex-col items-center text-center">
        <div className={`w-24 h-24 rounded-full mb-6 flex items-center justify-center transition-all ${isClockedIn ? 'bg-rose-50 text-rose-500' : 'bg-indigo-50 text-indigo-600'}`}>
          <Fingerprint size={48} />
        </div>
        <h2 className="text-2xl font-bold text-slate-800 mb-2">
          {isClockedIn ? 'Estàs treballant' : 'Bon dia!'}
        </h2>
        <p className="text-slate-500 mb-8 max-w-xs">
          {isClockedIn ? 'Recorda fitxar la sortida quan acabis la teva jornada.' : 'No oblidis registrar la teva entrada per avui.'}
        </p>
        <button 
          onClick={onClockAction}
          className={`w-full max-w-sm py-5 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all shadow-xl active:scale-95 ${
            isClockedIn 
              ? 'bg-rose-500 text-white shadow-rose-100' 
              : 'bg-indigo-600 text-white shadow-indigo-100 hover:bg-indigo-700'
          }`}
        >
          {isClockedIn ? <LogOut size={24} /> : <LogIn size={24} />}
          {isClockedIn ? 'Registrar Sortida' : 'Registrar Entrada'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Quick Stats */}
        <div className="lg:col-span-2 grid grid-cols-1 sm:grid-cols-2 gap-4">
          <StatCard 
            title="Temps Avui" 
            value={`${Math.floor(totalMinutesToday / 60)}h ${totalMinutesToday % 60}m`} 
            subtitle="Jornada de 8h"
            icon={<Clock className="text-indigo-600" />}
            progress={(totalMinutesToday / 480) * 100}
          />
          <StatCard 
            title="Últim Registre" 
            value={entries.length > 0 ? new Date(entries[entries.length - 1].timestamp).toLocaleTimeString('ca-ES', { hour: '2-digit', minute: '2-digit' }) : "--:--"} 
            subtitle={entries.length > 0 ? (entries[entries.length - 1].type === ClockType.IN ? 'Entrada registrada' : 'Sortida registrada') : 'Cap registre avui'}
            icon={entries[entries.length - 1]?.type === ClockType.IN ? <ArrowUpRight className="text-green-500" /> : <ArrowDownRight className="text-rose-500" />}
          />
        </div>

        {/* AI Insights Panel */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-2 mb-4">
            <Sparkles size={20} className="text-indigo-500" />
            <h3 className="font-bold text-slate-800">Assistent AI</h3>
          </div>
          {loadingAi ? (
            <div className="animate-pulse space-y-2">
              <div className="h-4 bg-slate-100 rounded w-full"></div>
              <div className="h-4 bg-slate-100 rounded w-5/6"></div>
              <div className="h-4 bg-slate-100 rounded w-4/6"></div>
            </div>
          ) : (
            <p className="text-sm text-slate-600 leading-relaxed italic">
              {aiInsights || "Encara no hi ha prou dades per generar un resum automàtic. Fitxa durant uns dies per veure la màgia!"}
            </p>
          )}
          <button 
              onClick={fetchInsights}
              className="mt-4 text-xs font-semibold text-indigo-600 hover:text-indigo-800"
          >
              Actualitzar anàlisi
          </button>
        </div>
      </div>

      {/* Recent Activity List */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">Activitat Recent</h3>
        </div>
        <div className="divide-y divide-slate-50">
          {entries.length === 0 ? (
            <div className="p-8 text-center text-slate-400">Encara no has fitxat avui</div>
          ) : (
            entries.slice(-5).reverse().map(entry => (
              <div key={entry.id} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-full ${entry.type === ClockType.IN ? 'bg-green-50 text-green-600' : 'bg-rose-50 text-rose-600'}`}>
                    {entry.type === ClockType.IN ? <LogIn size={14} /> : <LogOut size={14} />}
                  </div>
                  <div>
                    <p className="font-semibold text-sm">{entry.type === ClockType.IN ? 'Entrada' : 'Sortida'}</p>
                    <p className="text-xs text-slate-500">
                      {new Date(entry.timestamp).toLocaleDateString('ca-ES')} a les {new Date(entry.timestamp).toLocaleTimeString('ca-ES', { hour: '2-digit', minute: '2-digit' })}
                    </p>
                  </div>
                </div>
                {entry.location && (
                  <span className="text-[10px] bg-slate-100 px-2 py-1 rounded text-slate-500">GPS OK</span>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ title: string, value: string, subtitle: string, icon: React.ReactNode, progress?: number }> = ({ title, value, subtitle, icon, progress }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
    <div className="flex justify-between items-start mb-4">
        <div>
            <p className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">{title}</p>
            <h4 className="text-2xl font-bold text-slate-800">{value}</h4>
        </div>
        <div className="p-2 bg-slate-50 rounded-xl">
            {icon}
        </div>
    </div>
    <div className="flex items-center gap-2">
        {progress !== undefined && (
            <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 transition-all duration-500" style={{ width: `${Math.min(progress, 100)}%` }} />
            </div>
        )}
        <span className="text-xs text-slate-500">{subtitle}</span>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { 
  Clock, 
  Calendar as CalendarIcon, 
  BarChart3, 
  Settings, 
  LogIn, 
  LogOut,
  User,
  Power,
  ShieldCheck,
  Fingerprint
} from 'lucide-react';
import { ClockType, ClockEntry, VacationRequest, ViewType, UserState } from './types';
import Dashboard from './components/Dashboard';
import CalendarView from './components/CalendarView';
import Reports from './components/Reports';
import LoginScreen from './components/LoginScreen';
import SettingsView from './components/SettingsView';
import VacationAdmin from './components/VacationAdmin';
import { syncToSheets } from './sheetsService';

const App: React.FC = () => {
  const [user, setUser] = useState<UserState>({ 
    employeeCode: null, 
    employeeName: null, 
    isAuthenticated: false, 
    sheetsUrl: '',
    isAdmin: false
  });
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [allEntries, setAllEntries] = useState<ClockEntry[]>([]);
  const [allVacations, setAllVacations] = useState<VacationRequest[]>([]);
  const [isClockedIn, setIsClockedIn] = useState(false);

  // 1. CARREGAR DADES EN INICIAR
  useEffect(() => {
    const savedEntries = localStorage.getItem('horaripro_entries');
    const savedVacations = localStorage.getItem('horaripro_vacations');
    const savedSession = localStorage.getItem('horaripro_session');

    if (savedEntries) setAllEntries(JSON.parse(savedEntries));
    if (savedVacations) setAllVacations(JSON.parse(savedVacations));
    if (savedSession) {
      const session = JSON.parse(savedSession);
      // Carreguem la sessió tal qual (si estava loguejat, segueix loguejat)
      setUser(session);
    }
  }, []);

  // 2. GUARDAR DADES QUAN CANVIEN
  useEffect(() => {
    localStorage.setItem('horaripro_entries', JSON.stringify(allEntries));
    localStorage.setItem('horaripro_vacations', JSON.stringify(allVacations));

    if (user.employeeCode) {
      localStorage.setItem('horaripro_session', JSON.stringify(user));
    }
  }, [allEntries, allVacations, user]);

  useEffect(() => {
    if (user.employeeCode) {
      const entries = allEntries.filter(e => e.employeeCode === user.employeeCode);
      setIsClockedIn(entries.length > 0 && entries[entries.length - 1].type === ClockType.IN);
    }
  }, [allEntries, user.employeeCode]);

  const handleLogin = (code: string, name?: string) => {
    const isAdmin = code === '9999';
    setUser(prev => ({ 
      ...prev, 
      employeeCode: prev.employeeCode || code, // No canviem el codi si ja en teníem un
      employeeName: name || prev.employeeName, 
      isAuthenticated: true,
      isAdmin: isAdmin || prev.isAdmin
    }));
  };

  const handleLogout = () => {
    // marquem com a no autenticat i guardem immediatament
    const newState = { ...user, isAuthenticated: false };
    setUser(newState);
    localStorage.setItem('horaripro_session', JSON.stringify(newState));
  };

  const handleResetProfile = () => {
    if (window.confirm("Vols eliminar completament el teu perfil d'aquest dispositiu? Hauràs de tornar a introduir el teu nom i escollir un PIN la propera vegada.")) {
      localStorage.removeItem('horaripro_session');
      setUser({ employeeCode: null, employeeName: null, isAuthenticated: false, sheetsUrl: user.sheetsUrl, isAdmin: false });
    }
  };

  const handleClockAction = async () => {
    if (!user.employeeCode || !user.employeeName) return;
    const newType = isClockedIn ? ClockType.OUT : ClockType.IN;
    const newEntry: ClockEntry = {
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode,
      employeeName: user.employeeName,
      type: newType,
      timestamp: Date.now(),
      syncStatus: 'Pendent'
    };

    const updateWithGeo = (pos?: GeolocationPosition) => {
      if (pos) newEntry.location = { lat: pos.coords.latitude, lng: pos.coords.longitude };
      setAllEntries(prev => [...prev, newEntry]);
      if (user.sheetsUrl) {
        syncToSheets(newEntry, user.sheetsUrl).then(success => {
          if (success) {
            setAllEntries(prev => prev.map(e => e.id === newEntry.id ? { ...e, syncStatus: 'Sincronitzat' } : e));
          }
        });
      }
    };

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => updateWithGeo(pos), () => updateWithGeo());
    } else {
      updateWithGeo();
    }
  };

  const addVacation = (vac: Omit<VacationRequest, 'id' | 'status' | 'employeeCode' | 'employeeName'>) => {
    const newVac: VacationRequest = {
      ...vac,
      id: crypto.randomUUID(),
      employeeCode: user.employeeCode || '0000',
      employeeName: user.employeeName || 'Desconegut',
      status: 'Pendent'
    };
    setAllVacations(prev => [...prev, newVac]);
  };

  const updateVacationStatus = (id: string, status: 'Aprovada' | 'Denegada') => {
    setAllVacations(prev => prev.map(v => v.id === id ? { ...v, status } : v));
  };

  // SI NO ESTÀ AUTENTICAT, MOSTRAR PANTALLA DE PIN
  if (!user.isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} savedName={user.employeeName} savedCode={user.employeeCode} />;
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900 pb-20 md:pb-0">
      <nav className="w-full md:w-64 bg-white border-b md:border-r border-slate-200 p-4 flex md:flex-col gap-4 sticky top-0 z-30">
        <div className="flex items-center gap-2 mb-0 md:mb-8 px-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <Clock size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tight text-slate-900">HorariPro</h1>
        </div>

        <div className="flex md:flex-col gap-1 overflow-x-auto scrollbar-hide">
          <NavItem active={activeView === 'dashboard'} onClick={() => setActiveView('dashboard')} icon={<BarChart3 size={20} />} label="Inici" />
          <NavItem active={activeView === 'calendar'} onClick={() => setActiveView('calendar')} icon={<CalendarIcon size={20} />} label="Calendari" />
          <NavItem active={activeView === 'reports'} onClick={() => setActiveView('reports')} icon={<Clock size={20} />} label="Registres" />
          {user.isAdmin && <NavItem active={activeView === 'admin'} onClick={() => setActiveView('admin')} icon={<ShieldCheck size={20} />} label="Gestió" />}
          <NavItem active={activeView === 'settings'} onClick={() => setActiveView('settings')} icon={<Settings size={20} />} label="Config." />
        </div>

        <div className="hidden md:flex flex-col mt-auto gap-3 pt-4 border-t border-slate-100">
          <div className="p-3 bg-indigo-50 rounded-xl">
             <p className="text-[10px] font-bold text-indigo-700 uppercase truncate">{user.employeeName} {user.isAdmin && "(Admin)"}</p>
             <p className="text-[10px] text-slate-500">Actiu</p>
          </div>
          <button onClick={handleClockAction} className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-transform active:scale-95 ${isClockedIn ? 'bg-rose-500 text-white shadow-rose-100' : 'bg-indigo-600 text-white shadow-indigo-100 shadow-lg'}`}>
            {isClockedIn ? <LogOut size={18} /> : <LogIn size={18} />}
            {isClockedIn ? 'Sortida' : 'Entrada'}
          </button>
          <button onClick={handleLogout} className="text-xs text-slate-400 hover:text-rose-500 flex items-center justify-center gap-2 transition-colors py-2">
            <Power size={14} /> Tancar Sessió (Bloquejar)
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {activeView === 'dashboard' && <Dashboard entries={allEntries.filter(e => e.employeeCode === user.employeeCode)} isClockedIn={isClockedIn} onClockAction={handleClockAction} />}
          {activeView === 'calendar' && <CalendarView vacations={allVacations} currentUserId={user.employeeCode || ''} onAddVacation={addVacation} />}
          {activeView === 'reports' && <Reports entries={allEntries.filter(e => e.employeeCode === user.employeeCode)} employeeCode={user.employeeCode || ''} />}
          {activeView === 'admin' && <VacationAdmin vacations={allVacations} onUpdateStatus={updateVacationStatus} />}
          {activeView === 'settings' && <SettingsView sheetsUrl={user.sheetsUrl || ''} onUpdateUrl={(url) => setUser({...user, sheetsUrl: url})} onResetProfile={handleResetProfile} onClearHistory={() => setAllEntries([])} employeeName={user.employeeName || ''} />}
        </div>
      </main>

      {/* Botó flotant de fitxatge per a mòbils */}
      <div className="fixed bottom-6 right-6 md:hidden z-40">
        <button 
          onClick={handleClockAction} 
          className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 ${isClockedIn ? 'bg-rose-500 text-white ring-4 ring-rose-100' : 'bg-indigo-600 text-white ring-4 ring-indigo-100'}`}
        >
          {isClockedIn ? <LogOut size={28} /> : <Fingerprint size={28} />}
        </button>
      </div>
    </div>
  );
};

const NavItem = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium whitespace-nowrap ${active ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-100'}`}>
    {icon} <span>{label}</span>
  </button>
);

export default App;

import React, { useState } from 'react';
import { Lock, Delete, UserCircle, AlertCircle } from 'lucide-react';

interface LoginScreenProps {
  onLogin: (code: string, name?: string) => void;
  savedName: string | null;
  savedCode: string | null;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onLogin, savedName, savedCode }) => {
  const [pin, setPin] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState(false);
  const isFirstLogin = !savedName;

  const handleNumberClick = (num: string) => {
    if (pin.length < 4) {
      setError(false);
      const newPin = pin + num;
      setPin(newPin);

      if (newPin.length === 4) {
        // Cas 1: Registre inicial
        if (isFirstLogin) {
          if (!name.trim()) {
            alert("Per favor, introdueix el teu nom primer.");
            setPin('');
            return;
          }
          setTimeout(() => onLogin(newPin, name), 300);
        } 
        // Cas 2: Login recurrent (validació de PIN)
        else {
          // El PIN ha de coincidir amb el guardat o ser el codi d'admin 9999
          if (newPin === savedCode || newPin === '9999') {
            setTimeout(() => onLogin(newPin), 300);
          } else {
            setTimeout(() => {
              setError(true);
              setPin('');
              // Feedback de vibració si el navegador ho permet
              if ('vibrate' in navigator) navigator.vibrate(200);
            }, 300);
          }
        }
      }
    }
  };

  const handleDelete = () => {
    setError(false);
    setPin(pin.slice(0, -1));
  };

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className={`max-w-md w-full bg-white rounded-[2rem] shadow-2xl overflow-hidden p-6 sm:p-8 transition-all duration-300 ${error ? 'animate-shake border-2 border-rose-500' : ''}`}>
        <div className="flex flex-col items-center mb-6">
          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center mb-4 transition-colors ${error ? 'bg-rose-100 text-rose-600' : 'bg-indigo-100 text-indigo-600'}`}>
            {error ? <AlertCircle size={28} /> : isFirstLogin ? <UserCircle size={28} /> : <Lock size={28} />}
          </div>
          <h1 className="text-xl font-bold text-slate-800">
            {isFirstLogin ? 'Registre Inicial' : `Hola, ${savedName}`}
          </h1>
          <p className={`text-xs text-center mt-2 px-4 font-medium ${error ? 'text-rose-500' : 'text-slate-500'}`}>
            {error 
              ? 'PIN incorrecte. Torna-ho a provar.' 
              : isFirstLogin 
                ? 'Configura el teu nom i el PIN que vulguis utilitzar.' 
                : 'Introdueix el teu PIN per accedir.'}
          </p>
        </div>

        {isFirstLogin && (
          <div className="mb-6">
            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 px-1">Nom i Cognoms</label>
            <input 
              type="text" 
              placeholder="Ex: Joan Garcia i Mas"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-all"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>
        )}

        <div className="flex justify-center gap-3 mb-8">
          {[0, 1, 2, 3].map((i) => (
            <div
              key={i}
              className={`w-10 h-14 rounded-xl border-2 flex items-center justify-center text-xl font-bold transition-all ${
                pin.length > i 
                  ? (error ? 'border-rose-500 bg-rose-50 text-rose-600' : 'border-indigo-600 bg-indigo-50 text-indigo-600 scale-105') 
                  : 'border-slate-100 bg-slate-50 text-slate-300'
              }`}
            >
              {pin[i] ? '●' : ''}
            </div>
          ))}
        </div>

        <div className="grid grid-cols-3 gap-3">
          {['1', '2', '3', '4', '5', '6', '7', '8', '9'].map((num) => (
            <button
              key={num}
              onClick={() => handleNumberClick(num)}
              className="h-14 sm:h-16 rounded-2xl bg-slate-50 text-lg font-bold text-slate-700 active:bg-indigo-600 active:text-white transition-colors outline-none"
            >
              {num}
            </button>
          ))}
          <div />
          <button
            onClick={() => handleNumberClick('0')}
            className="h-14 sm:h-16 rounded-2xl bg-slate-50 text-lg font-bold text-slate-700 active:bg-indigo-600 active:text-white transition-colors outline-none"
          >
            0
          </button>
          <button
            onClick={handleDelete}
            className="h-14 sm:h-16 rounded-2xl bg-slate-50 text-rose-500 flex items-center justify-center active:bg-rose-500 active:text-white transition-colors outline-none"
          >
            <Delete size={20} />
          </button>
        </div>

        <div className="text-center mt-8">
            <p className="text-[10px] text-slate-300 uppercase font-bold tracking-widest">HorariPro Security</p>
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-8px); }
          75% { transform: translateX(8px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 0s 2;
        }
      `}</style>
    </div>
  );
};

export default LoginScreen;

import React, { useMemo, useState } from 'react';
import { ClockEntry, ClockType } from '../types';
import { Download, MapPin, Clock as ClockIcon, Calendar as CalendarIcon, CloudUpload, CheckCircle2, RefreshCw } from 'lucide-react';

interface ReportsProps {
  entries: ClockEntry[];
  employeeCode: string;
  onSyncPending?: () => Promise<void>;
}

interface Session {
  date: string;
  in?: ClockEntry;
  out?: ClockEntry;
}

const Reports: React.FC<ReportsProps> = ({ entries, employeeCode, onSyncPending }) => {
  const [isSyncing, setIsSyncing] = useState(false);

  // Organitzem els registres en "sessions" (Entrada + Sortida)
  const sessions = useMemo(() => {
    const result: Session[] = [];
    const sorted = [...entries].sort((a, b) => a.timestamp - b.timestamp);

    sorted.forEach(entry => {
      const dateKey = new Date(entry.timestamp).toLocaleDateString('ca-ES');

      if (entry.type === ClockType.IN) {
        result.push({ date: dateKey, in: entry });
      } else {
        const lastSessionWithoutOut = [...result].reverse().find(s => !s.out && s.date === dateKey);
        if (lastSessionWithoutOut) {
          lastSessionWithoutOut.out = entry;
        } else {
          result.push({ date: dateKey, out: entry });
        }
      }
    });

    return result.reverse();
  }, [entries]);

  const pendingCount = useMemo(() => {
    return entries.filter(e => e.syncStatus !== 'Sincronitzat').length;
  }, [entries]);

  const calculateDuration = (session: Session) => {
    if (session.in && session.out) {
      const diff = session.out.timestamp - session.in.timestamp;
      const hours = Math.floor(diff / 3600000);
      const minutes = Math.floor((diff % 3600000) / 60000);
      return `${hours}h ${minutes}m`;
    }
    return '--';
  };

  const handleManualSync = async () => {
    if (!onSyncPending || pendingCount === 0 || isSyncing) return;
    setIsSyncing(true);
    await onSyncPending();
    setIsSyncing(false);
  };

  const exportToCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,";
    csvContent += "Data;Hora Entrada;Loc Entrada;Hora Sortida;Loc Sortida;Durada;ID Unic\n";

    sessions.forEach(s => {
      const hEntrada = s.in ? new Date(s.in.timestamp).toLocaleTimeString('ca-ES') : "";
      const lEntrada = s.in?.location ? `${s.in.location.lat},${s.in.location.lng}` : "";
      const hSortida = s.out ? new Date(s.out.timestamp).toLocaleTimeString('ca-ES') : "";
      const lSortida = s.out?.location ? `${s.out.location.lat},${s.out.location.lng}` : "";
      const durada = calculateDuration(s);
      const idUnic = s.in?.id || s.out?.id || "";

      csvContent += `${s.date};${hEntrada};${lEntrada};${hSortida};${lSortida};${durada};${idUnic}\n`;
    });

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `HorariPro_Resum_${employeeCode}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
            <CalendarIcon size={24} />
          </div>
          <div>
            <h3 className="font-bold text-lg text-slate-800">Resum de Jornades</h3>
            <p className="text-sm text-slate-500">ID Empleat: {employeeCode}</p>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 w-full xl:w-auto">
          <button 
            onClick={handleManualSync}
            disabled={pendingCount === 0 || isSyncing}
            className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all shadow-md ${
              pendingCount > 0 
                ? 'bg-amber-500 text-white hover:bg-amber-600 shadow-amber-100' 
                : 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none'
            }`}
          >
            {isSyncing ? <RefreshCw size={18} className="animate-spin" /> : <CloudUpload size={18} />}
            {isSyncing ? 'Sincronitzant...' : `Pujar a Excel (${pendingCount})`}
          </button>

          <button 
            onClick={exportToCSV} 
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
          >
            <Download size={18} />
            Exportar CSV
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-6 py-5 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Data</th>
                <th className="px-6 py-5 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Entrada</th>
                <th className="px-6 py-5 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Sortida</th>
                <th className="px-6 py-5 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Durada</th>
                <th className="px-6 py-5 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-right">Estat Núvol</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {sessions.map((session, idx) => {
                const isSynced = (session.in ? session.in.syncStatus === 'Sincronitzat' : true) && 
                                 (session.out ? session.out.syncStatus === 'Sincronitzat' : true);

                return (
                  <tr key={`${session.date}-${idx}`} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-5">
                      <div className="font-bold text-slate-700">{session.date}</div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="flex flex-col items-center">
                        <span className="text-sm font-semibold text-green-600">
                          {session.in ? new Date(session.in.timestamp).toLocaleTimeString('ca-ES', { hour: '2-digit', minute: '2-digit' }) : '--:--'}
                        </span>
                        {session.in?.location && (
                          <span className="flex items-center gap-0.5 text-[8px] text-slate-400 mt-1">
                            <MapPin size={8} /> GPS OK
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="flex flex-col items-center">
                        <span className="text-sm font-semibold text-rose-500">
                          {session.out ? new Date(session.out.timestamp).toLocaleTimeString('ca-ES', { hour: '2-digit', minute: '2-digit' }) : '--:--'}
                        </span>
                        {session.out?.location && (
                          <span className="flex items-center gap-0.5 text-[8px] text-slate-400 mt-1">
                            <MapPin size={8} /> GPS OK
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-5 text-center">
                      <div className="inline-flex items-center gap-1.5 px-3 py-1 bg-slate-100 rounded-full text-xs font-bold text-slate-600">
                        <ClockIcon size={12} />
                        {calculateDuration(session)}
                      </div>
                    </td>
                    <td className="px-6 py-5 text-right">
                      {isSynced ? (
                        <div className="flex items-center justify-end gap-1 text-green-500">
                           <CheckCircle2 size={14} />
                           <span className="text-[10px] font-bold uppercase">Sincronitzat</span>
                        </div>
                      ) : (
                        <div className="flex items-center justify-end gap-1 text-amber-500">
                           <RefreshCw size={14} />
                           <span className="text-[10px] font-bold uppercase">Pendent</span>
                        </div>
                      )}
                    </td>
                  </tr>
                );
              })}
              {sessions.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-20 text-center text-slate-400 italic">
                    Encara no hi ha cap jornada registrada.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {pendingCount > 0 && (
        <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl flex items-start gap-3">
          <RefreshCw size={18} className="text-amber-500 mt-0.5 shrink-0" />
          <p className="text-xs text-amber-800 leading-relaxed">
            Tens <strong>{pendingCount} fitxatges</strong> que només estan guardats en aquest dispositiu. 
            Prem el botó de pujar per assegurar-te que l'empresa els rep al full d'Excel. 
            <em> Nota: L'Excel no duplicarà fitxatges encara que els pugis dues vegades.</em>
          </p>
        </div>
      )}
    </div>
  );
};

export default Reports;

import React, { useState, useEffect } from 'react';
import { 
  Clock, 
  Calendar as CalendarIcon, 
  BarChart3, 
  Settings, 
  LogIn, 
  LogOut,
  User,
  Power,
  ShieldCheck,
  Fingerprint
} from 'lucide-react';
import { ClockType, ClockEntry, VacationRequest, ViewType, UserState } from './types';
import Dashboard from './components/Dashboard';
import CalendarView from './components/CalendarView';
import Reports from './components/Reports';
import LoginScreen from './components/LoginScreen';
import SettingsView from './components/SettingsView';
import VacationAdmin from './components/VacationAdmin';
import { syncToSheets } from './sheetsService';

const App: React.FC = () => {
  const [user, setUser] = useState<UserState>({ 
    employeeCode: null, 
    employeeName: null, 
    isAuthenticated: false, 
    sheetsUrl: '',
    isAdmin: false
  });
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [allEntries, setAllEntries] = useState<ClockEntry[]>([]);
  const [allVacations, setAllVacations] = useState<VacationRequest[]>([]);
  const [isClockedIn, setIsClockedIn] = useState(false);

  useEffect(() => {
    const savedEntries = localStorage.getItem('horaripro_entries');
    const savedVacations = localStorage.getItem('horaripro_vacations');
    const savedSession = localStorage.getItem('horaripro_session');

    if (savedEntries) setAllEntries(JSON.parse(savedEntries));
    if (savedVacations) setAllVacations(JSON.parse(savedVacations));
    if (savedSession) {
      const session = JSON.parse(savedSession);
      setUser(session);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('horaripro_entries', JSON.stringify(allEntries));
    localStorage.setItem('horaripro_vacations', JSON.stringify(allVacations));

    if (user.employeeCode) {
      localStorage.setItem('horaripro_session', JSON.stringify(user));
    }
  }, [allEntries, allVacations, user]);

  useEffect(() => {
    if (user.employeeCode) {
      const entries = allEntries.filter(e => e.employeeCode === user.employeeCode);
      setIsClockedIn(entries.length > 0 && entries[entries.length - 1].type === ClockType.IN);
    }
  }, [allEntries, user.employeeCode]);

  const handleLogin = (code: string, name?: string) => {
    const isAdmin = code === '9999';
    setUser(prev => ({ 
      ...prev, 
      employeeCode: prev.employeeCode || code,
      employeeName: name || prev.employeeName, 
      isAuthenticated: true,
      isAdmin: isAdmin || prev.isAdmin
    }));
  };

