    const newState = { ...user, isAuthenticated: false };
    setUser(newState);
    localStorage.setItem('horaripro_session', JSON.stringify(newState));
  };

  const handleResetProfile = () => {
    if (window.confirm("Vols eliminar completament el teu perfil d'aquest dispositiu?")) {
      localStorage.removeItem('horaripro_session');
      setUser({ employeeCode: null, employeeName: null, isAuthenticated: false, sheetsUrl: user.sheetsUrl, isAdmin: false });
    }
  };

  const handleSyncPending = async () => {
    if (!user.sheetsUrl) {
      alert("Configura la URL de Google Sheets primer a Configuració.");
      return;
    }

    const pendingEntries = allEntries.filter(e => e.syncStatus !== 'Sincronitzat' && e.employeeCode === user.employeeCode);
