    for (const entry of pendingEntries) {
      const success = await syncToSheets(entry, user.sheetsUrl);
      if (success) {
        updatedEntries = updatedEntries.map(e => e.id === entry.id ? { ...e, syncStatus: 'Sincronitzat' } : e);
